      for(int j=3;j<x-1;j++) 
         if(isprime(x) && x%2==1) ++p;
   }
   for(int k=1;k<=p;k++) 
   {
      a[k]=p+1;
      for(int i=4;i<=p+1;i++) {
         if(a[i]%2==1 && isprime(a[i])) a[k]-=1;
      }
